import commonjs from "@rollup/plugin-commonjs";
import resolve from "@rollup/plugin-node-resolve";
import terser from "@rollup/plugin-terser";
import { optimizeCss, optimizeImports } from "carbon-preprocess-svelte";
import css from "rollup-plugin-css-only";
import svelte from "rollup-plugin-svelte";

const production = !process.env.ROLLUP_WATCH;

export default {
  input: "src/index.js",
  output: {
    sourcemap: !production,
    format: "iife",
    name: "app",
    file: "public/build/bundle.js",
    // Single-file IIFE cannot load extra chunks.
    // Dynamic imports (DatePicker flatpickr rangePlugin) must be inlined.
    inlineDynamicImports: true,
  },
  plugins: [
    svelte({
      preprocess: [optimizeImports()],
      compilerOptions: { dev: !production },
    }),
    resolve({ browser: true, dedupe: ["svelte"] }),
    commonjs(),
    css({ output: "bundle.css" }),
    production && terser(),
    production && optimizeCss(),
  ],
};

import fs from "node:fs";
import { BASE_URL, SITEMAP_PATH } from "./constants";
import { getComponentNames } from "./utils";

const urls: string[] = [];

urls.push(`
  <url>
    <loc>${BASE_URL}/</loc>
    <changefreq>weekly</changefreq>
    <priority>1.0</priority>
  </url>`);

for (const componentName of getComponentNames()) {
  urls.push(`
  <url>
    <loc>${BASE_URL}/components/${componentName}</loc>
    <changefreq>weekly</changefreq>
    <priority>0.8</priority>
  </url>`);
}

urls.push(`
  <url>
    <loc>${BASE_URL}/llms.txt</loc>
    <changefreq>weekly</changefreq>
    <priority>0.5</priority>
  </url>`);

urls.push(`
  <url>
    <loc>${BASE_URL}/llms-full.txt</loc>
    <changefreq>weekly</changefreq>
    <priority>0.5</priority>
  </url>`);

const sitemap = `<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">${urls.join("")}
</urlset>
`;

fs.writeFileSync(SITEMAP_PATH, sitemap);

console.log(`Sitemap generated with ${urls.length} URLs`);

import { defineConfig, devices } from "@playwright/test";

export default defineConfig({
  testDir: "./e2e",
  fullyParallel: true,
  workers: process.env.CI ? 3 : undefined,
  forbidOnly: !!process.env.CI,
  retries: process.env.CI ? 2 : 0,
  reporter: process.env.CI ? [["list"], ["github"]] : "list",
  use: {
    baseURL: "http://localhost:4173",
  },
  projects: process.env.CI
    ? [{ name: "chromium", use: { ...devices["Desktop Chrome"] } }]
    : [
        { name: "chromium", use: { ...devices["Desktop Chrome"] } },
        { name: "firefox", use: { ...devices["Desktop Firefox"] } },
        { name: "webkit", use: { ...devices["Desktop Safari"] } },
      ],
  webServer: {
    command: "bunx vite --config e2e/vite.config.ts --port 4173",
    port: 4173,
    reuseExistingServer: !process.env.CI,
  },
});

import fs from "node:fs/promises";
import prettier from "prettier";
import { PRESET_STYLES } from "shadcn-svelte/preset";

const prettierConfig = await prettier.resolveConfig(import.meta.url);
if (!prettierConfig) throw new Error("Failed to resolve prettier config.");

async function pullStyles() {
	await Promise.all(
		PRESET_STYLES.map(async (style) => {
			console.log(`Pulling upstream style ${style}...`);
			const stylePath = `https://raw.githubusercontent.com/shadcn-ui/ui/refs/heads/main/apps/v4/registry/styles/style-${style}.css`;
			const styleContent = await fetch(stylePath).then((res) => res.text());
			const styleFilePath = `src/lib/registry/styles/style-${style}.css`;

			const formatted = await prettier.format(styleContent, {
				parser: "css",
				filepath: styleFilePath,
				...prettierConfig,
			});

			await fs.writeFile(styleFilePath, formatted);
			console.log(`Wrote style ${style} to ${styleFilePath}`);
		})
	);
}

pullStyles();

import { resolveCommand } from "package-manager-detector/commands";
import type { Agent, Command, ResolvedCommand } from "package-manager-detector";

export const PACKAGE_MANAGERS: Agent[] = ["pnpm", "npm", "yarn", "bun"] as const;
export type PackageManager = (typeof PACKAGE_MANAGERS)[number];

export type PackageManagerCommand = Command | "create";

export function getCommand(
	pm: Agent,
	type: PackageManagerCommand,
	command: string | string[]
): ResolvedCommand {
	let args;
	if (typeof command === "string") {
		args = command.split(" ");
	} else {
		args = command;
	}

	// special handling for create
	if (type === "create") return { command: pm, args: ["create", ...args] };

	const cmd = resolveCommand(pm, type, args);

	// since docs are static any unresolved command is a code error
	if (cmd === null) throw new Error("Could not resolve command!");

	return cmd;
}
